                                                                                                            Plurimath::Math::Function::Hat.new(
                                                                                                              Plurimath::Math::Symbols::Symbol.new("e"),
                                                                                                            ),
                                                                                                            Plurimath::Math::Symbols::Symbol.new("z"),
                                                                                                          ),
                                                                                                        ]),
                                                                    ]),
