          \\begin{pmatrix}
            \\hat{e}_{\\xi} \\\\ \\hat{e}_{\\eta} \\\\ \\hat{e}_{\\zeta}
          \\end{pmatrix}
          = T
          \\begin{pmatrix}
            \\hat{e}_{x} \\\\ \\hat{e}_{y} \\\\ \\hat{e}_{z}
          \\end{pmatrix},
        LATEX
      end

      it "returns string of symbol" do
        expect(formula).to eq(expected_value.gsub(/\s/, ""))
